import React from 'react'
import OwnerPonds from '../../pages/owner/OwnerPonds'
import { useAuth } from '../../context/AuthContext'
import '../../styles/technician/technician-ponds.css'

const TechnicianPonds = () => {
  const { user } = useAuth()

  return (
    <OwnerPonds
      readOnly={true}
      allowCreate={false}
      allowAssign={false}
      allowEdit={false}
      allowDelete={false}
      allowConfirmRenovation={true}
      roleMode="TECHNICIAN"
      currentUser={user}
      pageTitle="Ao phụ trách"
      pageSubtitle="Danh sách ao bạn được phân công quản lý"
    />
  )
}

export default TechnicianPonds
